(window.webpackJsonp=window.webpackJsonp||[]).push([[353],{980:function(n,t){n.exports="\x3c!-- \ntitle: JavaScript\nsort: \n--\x3e \n\n## 常用功能\n\n```js\n// 对象转字符串\nJSON.stringify(obj)\n// 字符串转对象\nJSON.parse(str)\n// 深拷贝\nJSON.parse(JSON.stringify(obj))\n\n// 字符串转数字\nparseInt()\nparseFloat()\n// 数字转字符串\nstr.toString()\n\n// 批量替换\nstr.replace(/-/g, '')\n\n// 切片\nstr.slice(0, 4)\n\n// 排序\nitemList.sort((a,b)=>{\n  a.id-b.i\n})\n```\n\n## 递归\n\n```react\n// 对源数组进行操作\npeople.forEach(function (dude) {\n  dude.pickUpSoap();\n});\n\n// 返回新数组\nvar wallets = people.map(function (dude) {\n  return dude.wallet;\n});\n\n// 筛选\nvar fatWallets = wallets.filter(function (wallet) {\n  return wallet.money > 100;\n});\n```\n\n"}}]);